var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"흠...... 이렇게 하는 건가?","JPN":"ううむ……こうか？","ENG":"Hmm... Am I doing this correctly?","TWN":"呃……是這樣弄的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"셀카는 그다지 찍어본 적이 없어서 잘 나오고 있는 건지 모르겠군.","JPN":"自撮りの経験がないから、ちゃんと撮れているかどうかわからんな。","ENG":"I've never been much of a selfie person. I have no idea what I'm doing.","TWN":"我沒有很常自拍，所以不知道拍得好不好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 뭐, 아이돌 오디션 보는 것도 아닌데 너무 신경 쓸 필요는 없겠지?","JPN":"まあ、アイドルオーディションじゃあるまいし、そこまで気にすることないか。","ENG":"Well, It's not like I'm applying for a talent show. Who cares?","TWN":"但又不是偶像試鏡，應該沒什麼問題吧？"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"어차피 내용이 중요한 거니까...... 대충 보라고, 시청자 여러분.","JPN":"何せ中身のほうが大事だからな……細かいことは気にしないでくれ、ご覧の皆さん。","ENG":"It's the content that matters. So suck it up if this turns out to be an eyesore.","TWN":"反正重要的是內容…… 觀眾朋友們就隨便看看吧。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......누구야, 이건? 아저씨랑 좀 닮은 것 같은데.","JPN":"……これは誰？　おじさんに似てる気がするけど。","ENG":"Who's this? He looks quite similar to you.","TWN":"……這是誰啊？好像有點像大叔耶。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......내 형이다.","JPN":"……俺の兄貴だ。","ENG":"He's my brother.","TWN":"……他是我哥。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"형? 친형이라는 거야?","JPN":"兄貴？　実のお兄さんってこと？","ENG":"Your brother? You mean your biological brother?","TWN":"你哥？是親生哥哥嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 형은 아가씨처럼 카운터 능력자였지.","JPN":"ああ、兄貴は嬢ちゃんのようにカウンター能力者だったんだ。","ENG":"Yes. He was a Counter, just like you.","TWN":"是啊，我哥跟妳一樣是制裁者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금은 교통사고로 죽었지만.","JPN":"交通事故で死んじまったけどな。","ENG":"He was killed in a traffic accident.","TWN":"雖然因為交通事故死了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미, 미안해......","JPN":"あ、ご、ごめんなさい……","ENG":"S-sorry.","TWN":"抱、抱歉……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......교통사고라고요? 카운터 능력자가 말인가요?","JPN":"……交通事故？　カウンター能力者なのにですか？","ENG":"But... A traffic accident? Didn't you say he was a Counter?","TWN":"……你說交通事故？殺了一個制裁者？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 웃기지?","JPN":"そうさ、おかしいだろ？","ENG":"I did. Hilarious, huh?","TWN":"是啊，很搞笑吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 그게 정식 조사내용인 걸 어쩌겠어?","JPN":"けど、公式調査の結果がそうなんだからどうしようもねえ。","ENG":"But that's the official result of the investigation.","TWN":"但那就是調查結果，又有什麼辦法呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 몇 번이나 이의신청을 했지만 담당 조사관들은 들은 체도 하지 않더군.","JPN":"俺も何度も異議申し立てをしたが、担当調査官らはまったく聞く耳を持たなかったんだ。","ENG":"I filed an objection several times, but the investigators didn't even pretend to listen.","TWN":"雖然我對這件事提出了好幾次異議，但負責調查的官員們卻充耳不聞。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 입으로 말하긴 뭐하지만, 형은 꽤 괜찮은 인간이었어.","JPN":"俺が言うのも何なんだが、兄貴は結構いい奴でな。","ENG":"Though I say it myself, Ian was a decent human being.","TWN":"雖然我自己說有點那個啦，但我哥是個很好的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"카운터로서도, 학자로서도......","JPN":"カウンターとしても、学者としても……","ENG":"As a Counter, a scholar,","TWN":"不管是作為一個制裁者，還是一個學者……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 형제로서도.","JPN":"そして、兄としても。","ENG":"and as a brother.","TWN":"還有作為兄弟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 용병 노릇을 그만두지 못하는 건......","JPN":"俺が傭兵を辞められねえのは……","ENG":"The reason I'm still in the mercenary business","TWN":"我之所以無法放棄傭兵的工作....　"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 형의 죽음을 도저히 받아들일 수 없었기 때문이야.","JPN":"そんな兄貴の死を到底受け入れることができないからなんだ。","ENG":"is that I still can't accept Ian's death.","TWN":"是因為我無法接受哥哥的死亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래서 형의 죽음과 관련된 비밀이라면 뭐든 파헤치기 시작했고......","JPN":"兄貴の死と関係のあることなら、何でも調べてきたが……","ENG":"I tried to dig into anything that even seemed remotely related to his death,","TWN":"所以只要是與我哥的死亡相關的秘密，我都會開始著手調查……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"최근에 형의 동료였던 어떤 여자의 도움을 받아서 형이 남긴 유언을 입수하게 됐지.","JPN":"最近、兄貴の元同僚だった女性の協力で、兄貴の遺言を手に入れたんだ。","ENG":"and I ended up coming across his will, with the help of a woman who used to work with him.","TWN":"最近，我受到哥哥以前女同事的幫助，得到了哥哥留下的遺言。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"유언이라......","JPN":"遺言ですか……","ENG":"A will, huh?","TWN":"遺言啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 내용이었죠?","JPN":"どんな内容でしたか？","ENG":"What was it about?","TWN":"是什麼內容呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"직접 보라고. 본인이 설명해 줄 테니까.","JPN":"本人が説明してくれるから、直接見てみろ。","ENG":"See for yourself. He's going to explain himself.","TWN":"直接去看吧，本人會解釋清楚的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"우선은...... 그래.","JPN":"まずは……そうだな。","ENG":"Let's see... Right.","TWN":"首先……對了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"옛날 이야기부터 시작해야겠군.","JPN":"昔話から始めるとしようか。","ENG":"I should start with what happened to me a long time ago.","TWN":"要從很久之前開始說起了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"몇 년 전쯤이었나......?","JPN":"何年前だったかな……？","ENG":"It was several years ago","TWN":"大概是幾年前吧？"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"바에서 진탕 마시고 뻗어 있는 내게 한 남자가 찾아왔지.","JPN":"バーで酔いつぶれている私に、ある男が近づいてきたんだ。","ENG":"when this man came looking for me while I was drunk as hell at a bar.","TWN":"我在酒吧裡喝得爛醉，一個男人朝我走了過來。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>미스터 레지날드</color>라고 자기를 소개한 그 남자는 대뜸 내게 세상을 바꿔 볼 생각이 없느냐고 물어 보더군.","JPN":"<color=#ffd34c>ミスター・レジナルド</color>と名乗ったその男は、いきなり私に、世界を変えてみるつもりはないかと尋ねてきた。","ENG":"He called himself <color=#ffd34c>Mr. Reginald</color> and asked me if I was interested in changing the world.","TWN":"那個人自稱是<color=#ffd34c>傳奇先生</color>，並問我有沒有想要改變世界的想法。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"처음에는 웬 사기꾼인가 하고 생각했는데......","JPN":"最初は詐欺師まがいの奴かと思ったが……","ENG":"I initially thought he was some kind of a scammer,","TWN":"我剛開始覺得他是個騙子。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"이 친구가 보여 준 자료를 보고는 정신이 확 깨 버렸지 뭐야.","JPN":"その男が差し出した資料を見て、一気に目が覚めたさ。","ENG":"but what he showed me opened my eyes.","TWN":"但當這位朋友把資料拿給我看時，我整個人完全清醒了過來。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그건 도저히 생물이 살 수 없는 고밀도 침식파 환경에서 멀쩡히 뛰어 놀고 있는 실험용 생쥐들의 모습이었어.","JPN":"あれは生き物が到底生存できない高密度侵食波の環境下で、\\n普通に走り回っている実験用マウスの姿だった。","ENG":"It was footage of lab mice running around casually in an environment where the Corruption level had been raised beyond lethal limits.","TWN":"那是一個在生物根本無法生存的高密度侵蝕波環境中，一群實驗老鼠在玩耍的畫面。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그 남자는 이면세계를 사람이 살 수 있는 곳으로 개조하는 방법을 연구 중이라고 하더군.","JPN":"あの男は、裏世界の環境を人間が住めるようにしようと研究しているのだと言った。","ENG":"The man said he was researching ways to turn the Counterside into an inhabitable area.","TWN":"那個男人說他正在研究把異界改造成人們能夠生活的地方。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"시간은 걸리겠지만, 인류가 뻗어나갈 수 있는 신천지를 개척해서......","JPN":"時間はかかるだろうが、人類が生き延びられる新天地を切り開いて……","ENG":"He added that no matter how long it'd take, he was determined to cultivate the place","TWN":"雖然需要時間，但他想開拓人類得以延續的新天地。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"전쟁도, 기아도 없는 신세계를 만드는 것이 자신의 목표라고.","JPN":"戦争も、飢饉もない新世界を作るのが自分の目標だと。","ENG":"into a paradise where there would be no war or hunger.","TWN":"他說他的目標，是打造一個沒有戰爭、沒有饑餓的新世界。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하하하...... 나 같은 이상주의자에겐 도저히 피할 수 없는 미끼였지.","JPN":"ハハハ、私のような理想主義者には、とても魅力的な餌だったよ。","ENG":"Hah hah... It was an offer that an idealist like me couldn't refuse.","TWN":"哈哈哈……對於像我這樣的理想主義者來說，這還真是個無法拒絕的誘餌呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"이름도 꽤 멋졌어. 이면세계를 낙원으로 바꾸는 자들......","JPN":"タイトルのセンスもなかなかでね、「裏世界を楽園に変える者たち」……","ENG":"Even the name of the group was cool. The ones who will change the Counterside into a paradise...","TWN":"他們的名字也很酷，將異界改造成樂園的人…"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리플레이서</color>.","JPN":"<color=#ffd34c>リプレイサー</color>。","ENG":"The <color=#ffd34c>Replacers</color>.","TWN":"<color=#ffd34c>克隆集團</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서......! 설마......?","JPN":"リプレイサー……！　まさか……？","ENG":"R-Replacers? No, he's not saying...","TWN":"克隆集團……！ 難道……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"쉿. 이야기는 끝까지 보고 나서 해도 늦지 않아.","JPN":"しっ、最後まで聞いてから話しても遅くないぞ。","ENG":"Shh. Save your thoughts for after the end.","TWN":"噓，把話聽完再發作也不遲。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 한동안은 괜찮았어.","JPN":"それからしばらくの間は良かった。","ENG":"Everything was fine, at least for a while.","TWN":"之後有一段時間還不錯。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"민간조직이라고는 믿을 수 없을 정도의 자금 동원력이나 조직력......","JPN":"民間組織とは思えないほどの資金力や組織力……","ENG":"We raised funds like no other private organization could; all the members had a strong sense of unity...","TWN":"雖然是民間組織，但它有令人難以置信的資金和組織力....."},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 무엇보다 관리국 환경 연구부서에서 꽤 잘나가는 선임연구원이었던 나도 구경조차 못해 본 구 관리국의 아티팩트급 유물들을 넘치도록 제공해 줬거든.","JPN":"何せ管理局環境研究部署のエリート専任研究員だった私ですら、\\n見たこともない旧管理局のアーティファクト級の遺物を山ほど与えてくれたからな。","ENG":"And most of all, they provided me with tons of rare artifacts of the Old Administration, which even I, a former senior researcher of the Administration, had never come across before.","TWN":"而且最重要的是，他們提供了大量舊管理局的人造神器級遺物，是連我這個管理局環境研究部門的上級研究員都從未見過的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 시간이 지날수록 이상한 것들이 눈에 뜨이기 시작했어.","JPN":"しかし、時間が経つにつれて妙なものが目につくようになった。","ENG":"But as time passed, I started to notice weird things.","TWN":"但隨著時間的推移，一些奇怪的現象開始映入我的眼簾。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"도무지 출처를 알 수 없는 생체 조직에 대한 실험 자료들이 데이터베이스에 올라왔고......","JPN":"出所のわからないような生体組織に関する実験資料がデータベースに上がったり……","ENG":"There was data from biotests with untraceable sources in the database.","TWN":"資料庫裡，開始出現了一些完全無法得知來源的生物組織實驗資料。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"군사용이 분명한 보급 물자와 정체불명의 차원간 항해용 함선들이 연구소에 수시로 드나들더군.","JPN":"間違いなく軍事用とみられる補給品や、\\n次元間航海向けの正体不明の艦船が研究所に頻繁に出入りしていた。","ENG":"Military supplies were being carried in and out of the lab; unidentified ships for inter-dimensional navigation were frequenting the premises.","TWN":"明顯是軍事用的補給物資、身份不明的次元間航行用艦船，全都頻繁地出入研究所。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"결정적으로 내가 잘못된 선택을 했다는 것을 알게 된 건......","JPN":"自分が間違った選択をしたと確信したのは……","ENG":"More than everything, I knew that I've made a terrible decision","TWN":"最後讓我發現我做出了錯誤選擇的……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"놈들이 인간에 대한 실험을 하는 장면을 목격했기 때문이야.","JPN":"奴らが人体実験をするところを目撃したからだ。","ENG":"when I saw them carrying out an experiment on a live human.","TWN":"是我目擊了這些傢伙做人類實驗的場面。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"내가 맡은 연구는 특정 신호체계를 통해 침식체의 행동을 컨트롤하는 방법에 대한 것이었는데......","JPN":"私は、特定の信号システムを通して侵食体の行動を\\nコントロールする方法を研究していたんだが……","ENG":"The research I was in charge of was about manipulating C.O.s' behavior through a particular signal system,","TWN":"我負責的研究，是透過特定信號系統控制侵蝕體行為的方法……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그 핵심 회로를 인간에게 심는 장면을 우연히 보고 말았거든.","JPN":"そのコア回路を人間に埋め込むところをたまたま見かけてしまったんだ。","ENG":"and I accidentally witnessed them planting the core circuit in a human body.","TWN":"但我卻偶然撞見，他們將核心回路植入人體的場面。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"정확하게 이야기하면 이면세계에서 활동할 수 있는 인간...... 침식 융합체에게 말이지.","JPN":"正確には、裏世界で活動できる人間……侵食融合体に対してだったが。","ENG":"Or, to be exact, a body of a human who's able to operate in the Counterside: the Corruption hybrider.","TWN":"能夠在異界活動的人類，正確來說……就是指侵蝕融合體。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그제서야 난 확실히 알게 됐어.","JPN":"そこでようやく気づいたんだ。","ENG":"Everything was clear.","TWN":"這時我才終於明白。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"리플레이서라는 건, 이면세계를 낙원으로 대체하는 게 아니라......","JPN":"リプレイサーというのは、裏世界を楽園に変えるものではなく……","ENG":"The replacement they were talking about had nothing to do with turning the Counterside into a habitable environment.","TWN":"所謂的克隆集團，並不是把異界打造成樂園……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"인간을 자기들 마음대로 부릴 수 있는 침식 융합체로 대체하는 것이라는 걸.","JPN":"人間を好き勝手に操れる侵食融合体にするためのものだと。","ENG":"It was about changing human beings into mindless Corruption hybriders.","TWN":"而是將人類變成可以隨便他們使喚的侵蝕融合體。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"과연...... 그렇게 된 거였군요.","JPN":"なるほど……そういうことだったんですね。","ENG":"So that's what happened.","TWN":"果然……是這樣呢。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그때부터 나는 몰래 놈들을 저지할 수단을 준비하기 시작했지.","JPN":"それから私は、奴らを阻止する手段を密かに考え始めた。","ENG":"From that moment on, I started to devise a plan to stop them.","TWN":"從那個時候開始，我就悄悄地開始準備要阻止這些傢伙了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"놈들에겐 여러 가지 연구 목표가 있었는데, 개중에 가장 중요하게 추진했던 건......","JPN":"奴らには様々な研究目標があったが、そのなかで最も力を入れていたのは……","ENG":"They had several research goals, and the most important of them all was...","TWN":"他們有很多研究目標，而其中最需要推進的是……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"느리고 비효율적인 외과적 시술 없이도 현실세계의 인간을 대규모로 리플레이서 융합체로 만드는 방법.","JPN":"時間もかかって効率も悪い外科施術をせずに、\\n現実世界の人間を一気にリプレイサー融合体に変える方法。","ENG":"mass-converting humans in Normalside into Replacer hybriders without slow, inefficient surgical operations,","TWN":"不用那些又慢又沒效率的手術，就可以大量將現實世界的人變成克隆融合體的方法。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"일명 <color=#ffd34c>테라사이드 프로젝트</color>였어.","JPN":"通称<color=#ffd34c>テラサイドプロジェクト</color>。","ENG":"the <color=#ffd34c>Project Terraside</color>.","TWN":"別名為<color=#ffd34c>特拉賽德計畫</color>。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"이 시스템을 완성하기 위해서는 불멸체 코어라는 구 관리국의 유물이 필수적이지.","JPN":"このシステムを完成させるためには、不滅体コアという旧管理局の遺物が必要不可欠だった。","ENG":"And this project is just unviable without an artifact of the Old Administration called the Immortal System Core.","TWN":"為了完成這個系統，某個叫做不滅者核心的舊管理局遺物是不可或缺的。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 불멸체 코어를 작동시키려면 특수 인자로 만들어진 대량의 에너지원과 구 관리국의 시스템 통제용 코드 체계 해독이 필요해.","JPN":"だが、不滅体コアを作動させるには、特殊ファクターで作られた大量のエネルギー源とともに、\\n旧管理局でのシステム統制用のコード体系を解読する必要がある。","ENG":"To activate this Core, they need two things. One is a special factor that can generate massive energy, and the other is a code that can control the Old Administration system.","TWN":"但如果想要啟動不滅者核心，需要用特殊因子製造的大量能源，以及舊管理局的控制系統代碼體系化。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"다행히 아직까지는 이 두 가지 요소를 충족시키지 못했지만......","JPN":"幸いなことに、この二つの条件はまだ満たしていないが……","ENG":"Fortunately, they have been clueless as to how they could possibly work this out.","TWN":"慶幸的是，到目前為止，他們還沒能達成這兩個要素。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"최근에 우리에게 접근해 온 육익이라는 단체에서 그 문제를 해결할 방법을 가지고 있다고 하더군.","JPN":"最近我々に近づいてきた六翼という団体が、その問題の解決方法を有しているという。","ENG":"However, an organization named Six Wings recently contacted us and said they'd take care of it.","TWN":"但最近，一個叫“六翼”的團體向我們接觸，並說他們有辦法解決這個問題。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"물론 당장은 아니고 상당한 기간의 준비작업이 필요하다고는 하지만......","JPN":"もちろん今すぐではなく、相当な準備期間が必要とは言われているが……","ENG":"They say they need time for preparation,","TWN":"當然不是立刻，需要相當長期的準備作業。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"결국 언젠가는 목표를 달성하게 될 거야.","JPN":"いつかはきっと目標を達成するだろう。","ENG":"but it won't be long before they finally do it.","TWN":"但最終，他們總有一天會達成目標的。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그래서......","JPN":"そこで……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"나는 오늘 밤에 불멸체 코어를 탈취하여 파괴할 계획이다.","JPN":"私は今晩、不滅体コアを奪って破壊するつもりだ。","ENG":"I'm going to steal the Immortal System Core tonight and destroy it.","TWN":"我今晚計畫去奪取並破壞掉不滅者核心。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"무모해!","JPN":"そんなの無謀よ！","ENG":"That's plain reckless!","TWN":"太魯莽了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아무리 내부사정을 잘 알고 있다고 해도 혼자서 그런 일을 해낼 수 있을 리가 없잖아?","JPN":"いくら内部事情に詳しくても、たった一人でできるわけないじゃない。","ENG":"Even for an insider, that's not a job that can be done single-handedly!","TWN":"就算再怎麼瞭解內部狀況，這也不是一個人就能做到的事情吧？"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"설마 형님 되시는 분이 저것 때문에......?","JPN":"まさかお兄様はそれのせいで……？","ENG":"Was that how your brother...","TWN":"你哥哥該不會是因為這樣才會……？"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"내가 성공한다면...... 모든 게 해피엔딩으로 끝나게 되겠지.","JPN":"私が成功すれば……すべてはハッピーエンドで終わるだろう。","ENG":"If I succeed, it'd be a happy ending for everyone.","TWN":"如果我成功了……那就能以一個快樂結局收場了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 실패한다면......","JPN":"だが、失敗すれば……","ENG":"But if I fail...","TWN":"但要是我失敗的話……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"뭐, 이 비디오를 보고 있는 시점에서 난 실패했거나 죽었다는 뜻이겠군.","JPN":"まあ、この動画を見てる時点で、私は失敗してるか命を落としてるということになるな。","ENG":"Well, if you're watching this, you'll have to consider that I failed or died trying.","TWN":"不，當你們看到這個影片時，就代表我已經失敗，或是死了吧。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 너무 걱정하지는 말라고.","JPN":"だが、あまり案じることはない。","ENG":"But don't you worry too much.","TWN":"不過不需要太擔心。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"플랜 B는 언제나 준비되어 있으니까.","JPN":"プランBは常に用意してあるからな。","ENG":"I never do anything without a Plan B.","TWN":"因為我隨時都會準備Ｂ計畫。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"자세한 내용은 역탐지를 피하기 위해 세 개의 더미데이터로 나누어 각각 내 동료인 제인 도우의 개인 메일 계정과 리플레이서의 VPN 네트워크......","JPN":"詳しい内容は逆探知を避けるために3つのダミーデータに分けて、\\nそれぞれ仲間のジェーン・ドウの個人メールアカウントやリプレイサーのVPNネットワーク、","ENG":"I've divided the plan into three sets of dummy data and placed one in my colleague Jane Doe's personal mail account, another one in the VPN network of the Replacers,","TWN":"至於詳細內容，為了避免逆向搜索，我把內容分成了三組虛擬數據，分別透過我的同事，珍妮．多伊的個人信箱和克隆集團的VPN網路……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 어떤 간부 후보생의 몸에 탑재된 베리칩에 저장해 놓았다.","JPN":"そしてある幹部候補生の身体に埋め込まれたベリーチップに保存しておいた。","ENG":"and the last one on the VeriChip planted in one of the officer candidates.","TWN":"以及儲存在某個幹部候補生身上裝載的超級晶片裡。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"모르는 사람이 본다면 그저 쓰레기 데이터일 뿐이겠지만, 셋을 합치면......","JPN":"事情を知らない人から見ればただのゴミデータだろうが、その三つを合わせれば……","ENG":"They'd look like meaningless trash data to those who aren't in the know,","TWN":"不知情的人看到了，大概只會以為是些垃圾資料，但要是這三個合起來的話……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"적어도 놈들을 막을 수 있는 한 번의 기회 정도는 만들어 줄 거다.","JPN":"少なくとも奴らを阻止するチャンスを、一回くらいは作ってくれるだろう。","ENG":"but if you combine all three of them, it'd give you a chance to strike back.","TWN":"至少能創造一個可以阻止這些傢伙的機會。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"속죄...... 라고는 할 수 없겠지만......","JPN":"罪滅ぼし……とまでは言えないだろうが……","ENG":"I wouldn't say I'm doing this to expiate my sins,","TWN":"贖罪……應該不能這麼說吧……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"이 저주받을 계획을 도운 사람으로서, 최소한의 책임을 지는 거라고 생각해 주면 좋겠어.","JPN":"この呪われた計画に加担した者として、最低限の責任をとるものだと考えてほしい。","ENG":"but I'd be glad if you could think of this as my way of taking responsibility.","TWN":"但作為一個曾經協助過這個受詛咒計畫的人，我想要負起最起碼的責任。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그럼 잘 부탁하지, 시청자 여러분.","JPN":"それではよろしく頼むぞ、ご覧の皆さん。","ENG":"Then, whoever's watching, I bid you farewell.","TWN":"那就拜託你們了，看到這段影像的朋友們。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"꼭 세상을 지켜내기 바란다.","JPN":"必ず、この世界を守り抜いてくれ。","ENG":"I hope you'll be able to save the world.","TWN":"請你們一定要守護世界。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"아, 그리고 혹시라도...... 내 동생을 만난다면......","JPN":"あ、それから、もしも……私の弟に会ったら……","ENG":"And oh, by the way... if you ever do come across my brother...","TWN":"啊，對了……如果你們遇到我弟弟的話……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"같이 사업하자는 놈들은 다 사기꾼이니까, 형처럼 바보 같은 보이스 피싱에 낚이지 말라고 전해 주면 좋겠군.","JPN":"一緒に起業しようと誘ってくる奴なんか全員詐欺師に決まってるから、\\n兄のようにバカみたいな手口に騙されるなと伝えてくれ。","ENG":"Please tell him that all the bigmouths that want to get into business with him are liars, and not to get scammed like his stupid brother.","TWN":"請幫我轉告他，說要一起做大事業的人都是騙子，不要像哥哥這種蠢蛋一樣上當了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 사랑한다는 말도.","JPN":"あと、愛しているってこともな。","ENG":"And... tell him that I love him.","TWN":"還有告訴他我愛他。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨......","JPN":"おじさん……","ENG":"Mister...","TWN":"大叔……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 제인.","JPN":"それから、ジェーン。","ENG":"And Jane,","TWN":"另外珍妮。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"아마 이 영상을 보게 되면 넌 내게 미친 듯이 화를 내겠지만......","JPN":"この動画を見たら、君は怒り狂うだろうが……","ENG":"I know you'll be mad as hell if you ever get to see this,","TWN":"妳看到這個影片，大概會對我發飆吧。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"이렇게 위험한 일에 동료를 말려들게 할 순 없어서 말이지.","JPN":"こんな危険な仕事に仲間を巻き込むわけにはいかないんだ。","ENG":"but I just couldn't ask others for help in something this dangerous.","TWN":"畢竟我不希望我工作上的夥伴被捲入這麼危險的事情。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"만약 내가 실패한다면...... 뒤를 부탁한다.","JPN":"もし私が失敗したら……後を頼む。","ENG":"If I fail, please take care of things in my stead.","TWN":"但如果我失敗了的話……之後就拜託妳了。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"가급적이면 어딘가 멀리 도망쳐서 안전하게 살길 바라지만......","JPN":"できればどこか遠くへ逃げて、安全に暮らしてほしいが……","ENG":"I would really like to tell you to run and live on in safety...","TWN":"可以的話，希望妳能逃到很遠的地方，過上安全的生活。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"내가 아는 너라면 절대 그렇게 하지 않을 테니까.","JPN":"私の知る君なら、決してそうはしないだろうな。","ENG":"But I know too well that it's not something you're going to do.","TWN":"但我認識的妳絕對不會這麼做。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"당신은 포기나 굴복 따윈 모르는 정말 멋진 여자니까.","JPN":"君は諦めや屈服なんて言葉を知らない、本物のカッコいい女だからな。","ENG":"A strong, fine woman like you does not give in.","TWN":"因為妳是一個不知道什麼是放棄或屈服的好女孩。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"어차피 싸울 거라면...... 행운이 함께 하기를 빌게.","JPN":"どのみち戦うつもりなら……幸運を祈るよ。","ENG":"So for your future struggles, I wish you all the luck in the world.","TWN":"反正都要戰鬥的話……那不如就願好運與妳同在吧。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"당신의 영원한 친구, 이안으로부터.","JPN":"君の永遠の友、イアンより。","ENG":"These are the last words from your friend, Ian.","TWN":"妳永遠的朋友，伊恩。"},"stage":{"bg":"MAINSTREAM_5100010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잘 봤습니다. 메이슨 씨.","JPN":"見せていただきありがとうございます。メイソンさん。","ENG":"Thank you, Mr. Mason.","TWN":"我看完了，梅森先生。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일련의 의문들이 모두 해결되네요.","JPN":"一連の謎が一気に解けましたね。","ENG":"That answers a lot of questions.","TWN":"我一連串的疑問全部解決了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......선배?","JPN":"……先輩？","ENG":"Shiyoon?","TWN":"……前輩？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 리플레이서 간부 후보생......","JPN":"あのリプレイサー幹部候補生というのは……","ENG":"That officer candidate he was talking about...","TWN":"那個克隆集團幹部候補生……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이름은 나오지 않았지만, 아마 나이트였겠죠?","JPN":"名前こそ出ていないですが、おそらくナイトですよね？","ENG":"He didn't mention any names, but I'd assume it was Knight.","TWN":"雖然名字沒有提及，但大概是騎士吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그래.","JPN":"……そうだ。","ENG":"Yes.","TWN":"……對。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"KS-1에 잠입했던 것도, 나이트와 조우해서 베리칩의 정보를 빼내기 위해서였겠군요.","JPN":"KS-1に潜入したのも、ナイトと会ってベリーチップの情報を抜き取るためだったんでしょうね。","ENG":"So sneaking into KS-1 was to approach Knight and retrieve the data from her VeriChip.","TWN":"你潛入KS-1，也是為了遇到騎士，取得超級晶片的情報吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そのとおりだ。","ENG":"Exactly.","TWN":"對。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 굳이 리플레이서 간부의 몸에 데이터를 숨긴 건 이상하네요. 그럴 필요가 있었을까요?","JPN":"けど、あえてリプレイサー幹部の体にデータを隠したのは不自然ですね。\\nそんな必要あったのでしょうか。","ENG":"But why hide the data inside the body of a Replacer officer? I don't see how it was necessary.","TWN":"但刻意把數據藏在克隆集團幹部的身上，真是件怪事呢。有必要這樣做嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 형이지만 성격이 괴팍해서 말이야.","JPN":"俺の兄貴ながら、偏屈な性格でな。","ENG":"My brother had eccentric inclinations.","TWN":"他雖然是我的哥哥，但性格卻有點古怪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아마 그 녀석을 처치할 실력이 되지 않으면 애초에 시도도 하지 말라는 뜻이겠지.","JPN":"たぶん、奴を始末できる力がなけりゃ、そもそも手を出すなということだろう。","ENG":"Perhaps he wanted to say we shouldn't even try to stop the entire organization if we weren't strong enough to defeat her.","TWN":"他可能是想告訴我，如果連除掉這個傢伙的實力都沒有，那從一開始就不要去嘗試吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요. 그럼 제인 도우라는 분은 누구죠?","JPN":"なるほど、では、ジェーン・ドウという方は？","ENG":"I see. Who is this Jane Doe then?","TWN":"原來如此，但那個叫作珍妮．多伊的是誰啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"신원 미상이라니, 이름부터 심상치 않은데요.","JPN":"身元不明者を象徴する名前からして、並ならぬ印象ですね。","ENG":"I must say, it's a very odd name.","TWN":"不但身份不詳，光是名字就不太尋常。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......원래는 형과 함께 리플레이서 측에 연구원 겸 연락책으로 고용됐던 사람이다.","JPN":"……元々は兄とともに、リプレイサー側の研究員兼連絡係として雇われていた人物だ。","ENG":"She was the one who was hired as a researcher and liaison by the Replacer Syndicate with my brother.","TWN":"……她原本是跟哥哥一起被克隆集團錄用的研究員，並兼任聯絡窗口。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서에서 말인가요......?","JPN":"リプレイサー側に……？","ENG":"By the Replacers, you say?","TWN":"這是對克隆集團來說的意思嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다는 건...... 진짜 임무는 연락책이 아니라......","JPN":"ということは……本当の役目は連絡係ではなく……","ENG":"If that’s the case, her real duty was...","TWN":"這麼說的話……她真正的任務就不是當聯絡窗口……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 아마 감시역이었겠지.","JPN":"まあ、監視係だったろうよ。","ENG":"Yes. She was probably hired to keep an eye on him.","TWN":"沒錯，應該是監視者吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 무슨 심경의 변화가 있었는지 형이 죽은 후로 그녀도 리플레이서에 등을 돌린 것 같더군.","JPN":"だが、どういう風の吹き回しか兄貴の死後、彼女もリプレイサーに背を向けたようなんだ。","ENG":"But it seems she left the Syndicate after Ian's death, for whatever reason.","TWN":"但不知道她心理發生了什麼變化，哥哥死了之後，她好像也背叛了克隆集團。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 후에는 그녀 단독으로 테라사이드 시스템 관련 정보를 수집하고 있었고.","JPN":"それ以降、彼女は一人でテラサイドシステムに関する情報を集めていた。","ENG":"And she's been collecting information on System Terraside on her own ever since.","TWN":"之後她就一個人一直在收集和特拉賽德系統有關的情報。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 형의 유언을 입수한 것도 사실 그 여자를 통해서였어.","JPN":"実は兄貴の遺言も、その女から手に入れたんだ。","ENG":"As a matter of fact, it was through her that I was able to get Ian's video.","TWN":"事實上，我也是透過那個女的才能拿到我哥的遺言。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그분은 지금 어디에 있죠?","JPN":"彼女は今どこにいるんですか？","ENG":"Where is she now?","TWN":"那她現在在哪呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"모종의 장소에서 요양 중이지.","JPN":"某所で療養中だ。","ENG":"She's recovering, in a safe place.","TWN":"應該正在某地療養吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"얼마 전에 놈들의 기지에 침입해서 마지막 데이터 조각을 회수하느라 심하게 다쳤거든.","JPN":"この前、最後のデータを回収しようと奴らの基地に侵入した際に、大けがをしちまったんだ。","ENG":"She recently sustained severe wounds while trying to retrieve the last piece of the data from their base.","TWN":"不久前，她為了去回收最後的資料部分，闖入了那些傢伙的基地並受了重傷。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 그 데이터를 모아서 정확히 뭘 할 수 있는 거죠?","JPN":"では、そのデータを集めたら、実際何ができるんですか？","ENG":"What exactly can we do with all the data combined?","TWN":"那麼收集這些資料後，準確來說能做什麼呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......형이 준비해 둔 건 두 가지다.","JPN":"……兄貴が用意したのはこの二つだ。","ENG":"There are two things that my brother prepared.","TWN":"……哥哥準備了兩樣東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 총기함 뉴 오하이오에서 발신하는 불멸체 코어의 신호를 추적하는 법.","JPN":"リプレイサー総旗艦のニューオハイオから送信される、不滅体コアの信号を追跡する方法。","ENG":"One, the way to trace the signals of the Immortal System Core emitted from New Ohio, the flagship of the Replacer Syndicate.","TWN":"……一個是追蹤克隆集團總督旗艦新俄亥俄上的不滅者核心信號的方法。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 뉴 오하이오와 조우할 경우......","JPN":"さらに、ニューオハイオに遭遇した場合、","ENG":"And two, in case we encounter New Ohio...","TWN":"一個是和新俄亥俄遭遇時……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"놈들이 다시 도망치지 못하도록 함선의 차원도약 기능을 일시적으로 무력화시키는 백도어 코드.","JPN":"奴らが二度と逃げられないように、艦船の次元跳躍機能を一時的に無力化するバックドアコード。","ENG":"a backdoor code that'll make them unable to flee by temporarily disabling their ship's dimension jump system.","TWN":"防止他們再度逃跑，可以使艦船的次元躍遷機能暫時失效的後門代碼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......적들의 몸속에 시한폭탄을 심어두셨군요.","JPN":"……敵の体内に、時限爆弾を埋め込んでおいたのですね。","ENG":"So he set the time bomb within the heart of our enemy.","TWN":"……這可真是在敵人的內部埋下了定時炸彈呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 셈이지.","JPN":"まあ、そんなところだ。","ENG":"Pretty much.","TWN":"算是吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 우리가 해야 할 일은 뭐죠?","JPN":"それで、僕たちの役割は何でしょう？","ENG":"So what do we have to do?","TWN":"所以我們要做的事情是什麼呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우선은 준비물을 좀 모아야 해.","JPN":"まずは素材を集める必要がある。","ENG":"We have to gather up some stuff.","TWN":"首先，我們得準備一些東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"불멸체 코어의 신호 추적을 위해서는 순도 높은 대량의 이터니움 결정이 필요하거든.","JPN":"不滅体コアの信号を追跡するためには、高純度のエタニウム結晶が大量に必要なんだ。","ENG":"We need pure Eternium crystals to trace the Immortal System Core signals. A lot of them.","TWN":"為了追蹤不滅者核心的信號，我們需要大量的高純度永恆之金結晶。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대량이라니...... 얼마나 필요한 거죠?","JPN":"大量というと……どれくらいですか？","ENG":"By a lot, how much are you saying?","TWN":"大量……大概需要多少？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어지간한 양이라면 경찰청에서 지원해 줄 수 있을 겁니다.","JPN":"並みの量でしたら、警察庁から支援を受けられると思います。","ENG":"The police agency will be able to provide some for us.","TWN":"如果數量在合理範圍內的話，警察廳應該會給予支援的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 비상사태를 위해 쓸 수 있는 긴급예산이 편성되어 있으니까요.","JPN":"今回のような非常事態のために組まれた緊急予算がありますからね。","ENG":"They have budgets spared for emergencies like this.","TWN":"畢竟為了應對這種緊急情況，我們會編列一定的預算。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......대략 100kg 정도?","JPN":"……だいたい100kg位かな？","ENG":"Around a hundred kilos.","TWN":"……大概100公斤左右？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"풉......!!","JPN":"げっ……！！","ENG":"What?","TWN":"噗……！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"미, 미쳤어요?! 그건 국가예산 규모잖아요!","JPN":"ほ、本気ですか！？　それって国家予算並みじゃないですか！","ENG":"A-are you crazy? That's almost a year's national budget!","TWN":"你、你瘋了嗎？！那不是國家預算的規模嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 평소라면 도저히 구할 수 없는 양이긴 하지.","JPN":"まあ、通常なら到底調達できそうもない量だよな。","ENG":"Well, it sure is an enormous amount.","TWN":"也是，這個數量一般根本無法取得。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 마침 그 정도의 이터니움을 제공해 줄 수 있는 친구들 이야기를 들었거든.","JPN":"けど、ちょうどそれくらいのエタニウムを提供してくれる奴らの話を聞きつけたんだ。","ENG":"But I hear there's a group of people who could get us that much Eternium.","TWN":"不過，最近我聽說有些朋友正好能提供這麼多的永恆之金。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러니 일단 그 친구들을 만나 보자고.","JPN":"だから、一応そいつらに会ってみようと思ってな。","ENG":"I say we meet up with these fellas.","TWN":"那我們就先去見見他們吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};